// AUTO-GENERATED DRAFT SCREEN: AuditReportsScreen

import React, { useState, useEffect } from 'react';
import { cn } from '../lib/utils'; // Assuming cn utility for shadcn/ui

// Placeholder for tRPC hooks - in a real app, these would be generated by tRPC
interface AuditReport {
  id: string;
  title: string;
  date: string;
  status: 'completed' | 'pending' | 'failed';
  auditor: string;
  link: string;
}

interface UseAuditReportsResult {
  data: AuditReport[] | undefined;
  isLoading: boolean;
  isError: boolean;
  error: Error | null;
}

// Simulate tRPC hook for fetching audit reports
const useAuditReports = (): UseAuditReportsResult => {
  const [data, setData] = useState<AuditReport[] | undefined>(undefined);
  const [isLoading, setIsLoading] = useState(true);
  const [isError, setIsError] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    const fetchReports = async () => {
      try {
        // Simulate API call delay
        await new Promise(resolve => setTimeout(resolve, 1500));
        const mockReports: AuditReport[] = [
          { id: '1', title: 'Smart Contract Security Audit Q1 2026', date: '2026-03-15', status: 'completed', auditor: 'CertiK', link: '#' },
          { id: '2', title: 'Tokenomics Review V2', date: '2026-02-28', status: 'completed', auditor: 'PeckShield', link: '#' },
          { id: '3', title: 'Cross-Chain Bridge Audit', date: '2026-01-20', status: 'pending', auditor: 'Trail of Bits', link: '#' },
          { id: '4', title: 'DAO Governance Module Audit', date: '2025-12-01', status: 'completed', auditor: 'Quantstamp', link: '#' },
          { id: '5', title: 'Liquidity Pool Security Analysis', date: '2026-04-10', status: 'failed', auditor: 'Halborn', link: '#' },
        ];
        setData(mockReports);
      } catch (err) {
        setIsError(true);
        setError(err as Error);
      } finally {
        setIsLoading(false);
      }
    };
    fetchReports();
  }, []);

  return { data, isLoading, isError, error };
};

const AuditReportsScreen: React.FC = () => {
  const { data: reports, isLoading, isError, error } = useAuditReports();

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-50 dark:bg-gray-950 text-gray-900 dark:text-gray-100">
        <p className="text-lg">Loading audit reports...</p>
      </div>
    );
  }

  if (isError) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-red-50 dark:bg-red-950 text-red-800 dark:text-red-200 p-4">
        <p className="text-lg font-semibold">Error loading reports: {error?.message || 'Unknown error'}</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-950 p-6 sm:p-10 lg:p-16">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-4xl font-extrabold text-gray-900 dark:text-white mb-8 text-center">
          Crypto: Audit Reports
        </h1>

        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {reports?.map((report) => (
            <a
              key={report.id}
              href={report.link}
              target="_blank"
              rel="noopener noreferrer"
              className={cn(
                "block p-6 rounded-lg shadow-lg transition-all duration-300 ease-in-out",
                "bg-white dark:bg-gray-800 hover:shadow-xl hover:scale-[1.02]",
                "focus:outline-none focus:ring-4 focus:ring-blue-300 dark:focus:ring-blue-700",
                report.status === 'failed' && 'border-l-4 border-red-500',
                report.status === 'pending' && 'border-l-4 border-yellow-500',
                report.status === 'completed' && 'border-l-4 border-green-500'
              )}
              aria-label={`View audit report: ${report.title}`}
            >
              <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">{report.title}</h2>
              <p className="text-sm text-gray-600 dark:text-gray-400 mb-1">Auditor: {report.auditor}</p>
              <p className="text-sm text-gray-600 dark:text-gray-400 mb-3">Date: {report.date}</p>
              <span
                className={cn(
                  "inline-flex items-center px-3 py-1.5 rounded-full text-xs font-medium",
                  report.status === 'completed' && 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200',
                  report.status === 'pending' && 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200',
                  report.status === 'failed' && 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200'
                )}
              >
                {report.status.charAt(0).toUpperCase() + report.status.slice(1)}
              </span>
            </a>
          ))}
        </div>

        {reports && reports.length === 0 && (
          <p className="text-center text-gray-600 dark:text-gray-400 mt-8">No audit reports found.</p>
        )}
      </div>
    </div>
  );
};

export default AuditReportsScreen;
